// Base handler with default chaining
class Approver {
  constructor(name, limit) {
    this.name = name;
    this.limit = limit;
    this.next = null;
  }

  setNext(handler) {
    this.next = handler;
    return handler; // enables fluent chaining
  }

  approve(amount) {
    if (amount <= this.limit) {
      console.log(`${this.name} approved $${amount}`);
    } else if (this.next) {
      this.next.approve(amount);
    } else {
      console.log(`No one can approve $${amount}`);
    }
  }
}

class TeamLead extends Approver { constructor() { super('Team Lead', 1000); } }
class Manager  extends Approver { constructor() { super('Manager', 10000); } }
class Director  extends Approver { constructor() { super('Director', 100000); } }

// Usage
const lead = new TeamLead();
const manager = new Manager();
const director = new Director();

lead.setNext(manager).setNext(director);

lead.approve(800);     // Team Lead approved $800
lead.approve(5000);    // Manager approved $5000
lead.approve(90000);   // Director approved $90000
lead.approve(500000);  // No one can approve $500000

