from __future__ import annotations
from abc import ABC


class Approver(ABC):
    def __init__(self, name: str, limit: int) -> None:
        self.name = name
        self.limit = limit
        self._next: Approver | None = None

    def set_next(self, handler: Approver) -> Approver:
        self._next = handler
        return handler  # enables fluent chaining

    def approve(self, amount: int) -> None:
        if amount <= self.limit:
            print(f'{self.name} approved ${amount}')
        elif self._next:
            self._next.approve(amount)
        else:
            print(f'No one can approve ${amount}')


class TeamLead(Approver):
    def __init__(self) -> None:
        super().__init__('Team Lead', 1_000)


class Manager(Approver):
    def __init__(self) -> None:
        super().__init__('Manager', 10_000)


class Director(Approver):
    def __init__(self) -> None:
        super().__init__('Director', 100_000)


# Usage
lead = TeamLead()
manager = Manager()
director = Director()

lead.set_next(manager).set_next(director)

lead.approve(800)      # Team Lead approved $800
lead.approve(5_000)    # Manager approved $5000
lead.approve(90_000)   # Director approved $90000
lead.approve(500_000)  # No one can approve $500000
